import{_ as a,o as t,c as s,a0 as i}from"./chunks/framework.jwovEGr5.js";const u=JSON.parse('{"title":"Assign Plans Directly","description":"","frontmatter":{},"headers":[],"relativePath":"admin/assign-plans.md","filePath":"admin/assign-plans.md"}'),r={name:"admin/assign-plans.md"};function o(n,e,l,h,p,c){return t(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="assign-plans-directly" tabindex="-1">Assign Plans Directly <a class="header-anchor" href="#assign-plans-directly" aria-label="Permalink to &quot;Assign Plans Directly&quot;">​</a></h1><p>This guide is for <code>Supreme Admin</code> users only.</p><p>Direct assignment is the fast admin path for putting a plan on a kingdom or alliance from the subscriptions dashboard.</p><blockquote><p>Screenshot placeholder: <code>subs-assign.png</code> (S63)</p></blockquote><h2 id="use-with-care" tabindex="-1">Use with care <a class="header-anchor" href="#use-with-care" aria-label="Permalink to &quot;Use with care&quot;">​</a></h2><p>Direct assignment <strong>bypasses the normal request and payment workflow</strong>.</p><p>That makes it useful when:</p><ul><li>payment was already handled outside the app</li><li>you are setting up a new kingdom from scratch</li><li>you are correcting an admin-side subscription state</li></ul><p>It is not the normal customer-facing path. The normal path is still:</p><ol><li><a href="./../subscriptions/request-subscription.html">Request a Subscription</a></li><li><a href="./../subscriptions/payment-instructions.html">Payment Instructions &amp; Completing a Request</a></li><li><a href="./subscription-requests.html">Handle Subscription Requests</a></li></ol><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><p>From the <a href="./subscriptions-dashboard.html">Subscriptions &amp; Usage Manager</a>:</p><ol><li>Open the relevant kingdom or alliance row.</li><li>Choose <strong>Assign</strong>.</li><li>Select a compatible plan.</li><li>Confirm the assignment.</li></ol><p>The modal only offers plans compatible with that subject type.</p><h2 id="when-to-prefer-this-over-the-request-flow" tabindex="-1">When to prefer this over the request flow <a class="header-anchor" href="#when-to-prefer-this-over-the-request-flow" aria-label="Permalink to &quot;When to prefer this over the request flow&quot;">​</a></h2><p>Use direct assignment when the subscription decision is already settled and you do not need a message-thread record of the request.</p><p>If you need a clearer approval trail, stay in the request workflow instead.</p>',17)])])}const m=a(r,[["render",o]]);export{u as __pageData,m as default};
